calculators.compute:
var adj = v.basis + v.improve - v.depr;
var gain = Math.max(0, v.sale - adj);
var rec = Math.min(Math.max(0, v.depr), gain);
var cap = Math.max(0, gain - rec);
var recTax = rec * 0.25;
var capTax = cap * (v.fed / 100);
var niit = v.niit ? gain * 0.038 : 0;
var st = gain * (v.state / 100);
var total = recTax + capTax + niit + st;
return [
  {label:"Total gain", display:money(gain)},
  {label:"Depreciation recapture (25%)", display:money(recTax)},
  {label:"Federal capital-gains tax", display:money(capTax)},
  {label:"Net investment income tax (3.8%)", display:money(niit)},
  {label:"State tax", display:money(st)},
  {label:"Tax a 1031 exchange could defer", display:money(total), total:true}
];

var equityFromSale = Math.max(0, v.sale - v.oldDebt);
var equityIntoRep = Math.max(0, v.repPrice - v.newDebt);
var cashBoot = Math.max(0, equityFromSale - equityIntoRep);
var addlCash = Math.max(0, equityIntoRep - equityFromSale);
var mortgageBoot = Math.max(0, (v.oldDebt - v.newDebt) - addlCash);
var totalBoot = cashBoot + mortgageBoot;
var taxable = Math.min(totalBoot, Math.max(0, v.gain));
var tax = taxable * (v.rate / 100);
return [
  {label:"Cash boot (proceeds kept)", display:money(cashBoot)},
  {label:"Mortgage boot (net debt relief)", display:money(mortgageBoot)},
  {label:"Total boot", display:money(totalBoot)},
  {label:"Taxable boot (up to your gain)", display:money(taxable)},
  {label:"Estimated tax on boot", display:money(tax), total:true}
];

var rec = Math.min(Math.max(0, v.depr), Math.max(0, v.gain));
var tax = rec * (v.rate / 100);
return [
  {label:"Depreciation subject to recapture", display:money(rec)},
  {label:"Recapture rate", display:v.rate.toFixed(2) + "%"},
  {label:"Estimated recapture tax", display:money(tax), total:true}
];

var netSale = Math.max(0, v.sale - v.costs);
var equity = Math.max(0, netSale - v.oldDebt);
return [
  {label:"Net sale price (value to replace)", display:money(netSale)},
  {label:"Minimum replacement value", display:money(netSale)},
  {label:"Equity to reinvest", display:money(equity)},
  {label:"Minimum replacement debt", display:money(v.oldDebt), total:true}
];

if (!v.date) return [{label:"Enter your sale closing date", display:"—"}];
var d = new Date(v.date + "T00:00:00");
if (isNaN(d.getTime())) return [{label:"Invalid date", display:"—"}];
function fmtd(x){ return x.toLocaleDateString("en-US",{year:"numeric",month:"long",day:"numeric"}); }
function add(days){ var x = new Date(d.getTime()); x.setDate(x.getDate() + days); return x; }
return [
  {label:"Sale closes", display:fmtd(d)},
  {label:"45-day identification deadline", display:fmtd(add(45))},
  {label:"180-day closing deadline", display:fmtd(add(180)), total:true}
];

var annual = v.invest * (v.rate / 100);
var monthly = annual / 12;
return [
  {label:"Annual distribution", display:money(annual)},
  {label:"Monthly distribution", display:money(monthly)},
  {label:"Annual yield", display:v.rate.toFixed(2) + "%", total:true}
];

var cap = v.value > 0 ? (v.noi / v.value) * 100 : 0;
return [
  {label:"Net operating income", display:money(v.noi)},
  {label:"Property value", display:money(v.value)},
  {label:"Capitalization rate", display:cap.toFixed(2) + "%", total:true}
];

var coc = v.invested > 0 ? (v.cashflow / v.invested) * 100 : 0;
return [
  {label:"Annual pre-tax cash flow", display:money(v.cashflow)},
  {label:"Total cash invested", display:money(v.invested)},
  {label:"Cash-on-cash return", display:coc.toFixed(2) + "%", total:true}
];

var gain = Math.max(0, v.sale - v.basis);
var rec = Math.min(Math.max(0, v.depr), gain);
var cap = Math.max(0, gain - rec);
var tax = rec * 0.25 + cap * (v.fed / 100) + (v.niit ? gain * 0.038 : 0) + gain * (v.state / 100);
var afterTax = v.sale - tax;
return [
  {label:"Total gain", display:money(gain)},
  {label:"Estimated tax if you sell", display:money(tax)},
  {label:"Net proceeds after a taxable sale", display:money(afterTax)},
  {label:"Proceeds working in a 1031 exchange", display:money(v.sale), total:true}
];

var taxablePortion = v.yield * (1 - v.sheltered / 100);
var afterTax = v.yield - taxablePortion * (v.rate / 100);
var teq = v.rate < 100 ? afterTax / (1 - v.rate / 100) : afterTax;
return [
  {label:"Stated distribution yield", display:v.yield.toFixed(2) + "%"},
  {label:"After-tax yield", display:afterTax.toFixed(2) + "%"},
  {label:"Taxable-equivalent yield", display:teq.toFixed(2) + "%", total:true}
];
